#include <stdio.h>
#include <string.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char team1[20], team2[20], team3[20], team4[20];
        int score1, score2, score3, score4;
        scanf("%s %d", team1, &score1);
        scanf("%s %d", team2, &score2);
        scanf("%s %d", team3, &score3);
        scanf("%s %d", team4, &score4);
        if (strcmp(team1, "RealMadrid") == 0 && score1 < score2 && strcmp(team3, "Barcelona") == 0 && score3 > score4) {
            printf("Barcelona\n");
        } else {
            printf("RealMadrid\n");
        }
    }
    return 0;
}

